can grade(score: int) -> str {
    if score >= 90 {
        return "excellent";
    } else {
        if score >= 50 {
            return "passing";
        } else {
            return "retry";
        }
    }
}

with entry {
    print(grade(72));
}

node Counter {
    has value: int = 0;

    can add(step: int) -> int {
        self.value += step;
        return self.value;
    }
}

with entry {
    c = Counter(value=10);
    print(c.add(5));
}

import:py from math { sqrt; }

can hypotenuse(a: float, b: float) -> float {
    return sqrt(a * a + b * b);
}

with entry {
    print(hypotenuse(3.0, 4.0));
}

can sum_even(limit: int) -> int {
    total = 0;
    for i in range(limit + 1) {
        if i % 2 == 0 {
            total += i;
        }
    }
    return total;
}

with entry {
    print(sum_even(10));
}
